def calculate_ha(klines):
    if not klines:
        return None
    
    # Initial candle
    o = float(klines[0][1])
    h = float(klines[0][2])
    l = float(klines[0][3])
    c = float(klines[0][4])
    
    haOpen = (o + c) / 2
    haClose = (o + h + l + c) / 4
    
    for i in range(1, len(klines)):
        k = klines[i]
        o = float(k[1])
        h = float(k[2])
        l = float(k[3])
        c = float(k[4])
        
        currentHaClose = (o + h + l + c) / 4
        currentHaOpen = (haOpen + haClose) / 2
        
        haOpen = currentHaOpen
        haClose = currentHaClose
        
    return haOpen, haClose

haOpen, haClose = calculate_ha(data)
print(f"HA Open: {haOpen}")
print(f"HA Close: {haClose}")
print(f"Current State: {'Bullish (Green)' if haClose > haOpen else 'Bearish (Red)'}")
